#include <stdio.h>
#include <stdlib.h>

static int ctz(unsigned int x){
    int cnt = 0;
    while((x & 1) == 0){ cnt++; x >>= 1; }
    return cnt;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, Q; scanf("%d %d", &N, &Q);
        int *a = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        long long *diff = (long long*)calloc(N+2, sizeof(long long));
        for(int i=0;i<Q;i++){
            int l,r; unsigned int x; scanf("%d %d %u", &l, &r, &x);
            int add = ctz(x);
            diff[l-1] += add;
            diff[r]   -= add;
        }
        long long cur = 0; long long ans = 0;
        for(int i=0;i<N;i++){
            cur += diff[i];
            int base = ctz((unsigned int)a[i]);
            long long total = base + cur;
            if(total > ans) ans = total;
        }
        printf("%lld\n", ans);
        free(a); free(diff);
    }
    return 0;
}

