const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = data[idx++];
let outputs = [];
function ctz(x){
  let cnt = 0;
  while ((x & 1) === 0){ cnt++; x >>>= 1; }
  return cnt;
}
for(let t=0; t<T; t++){
  const N = data[idx++];
  const Q = data[idx++];
  const a = new Array(N);
  for(let i=0;i<N;i++) a[i] = data[idx++];
  const diff = new Array(N+1).fill(0);
  for(let i=0;i<Q;i++){
    const l = data[idx++];
    const r = data[idx++];
    const x = data[idx++];
    const add = (x & -x).toString(2).length - 1; // trailing zeros
    diff[l-1] += add;
    diff[r]   -= add;
  }
  let cur = 0, ans = 0;
  for(let i=0;i<N;i++){
    cur += diff[i];
    const base = (a[i] & -a[i]).toString(2).length - 1;
    const total = base + cur;
    if(total > ans) ans = total;
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));

